import{_ as t,o as r,c as s,j as e,a as n,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"十八铜人的折凳","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/近战武器/0.无支线/十八铜人的折凳.md","filePath":"4.资源分区/7.物品与装备/2.武器/近战武器/0.无支线/十八铜人的折凳.md"}'),d={name:"4.资源分区/7.物品与装备/2.武器/近战武器/0.无支线/十八铜人的折凳.md"};function p(_,a,l,i,c,h){return r(),s("div",null,[...a[0]||(a[0]=[e("h1",{id:"十八铜人的折凳",tabindex:"-1"},[n("十八铜人的折凳 "),e("a",{class:"header-anchor",href:"#十八铜人的折凳","aria-label":'Permalink to "十八铜人的折凳"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新秩序006")])])],-1),o('<h1 id="十八铜人的折凳-1" tabindex="-1">十八铜人的折凳 <a class="header-anchor" href="#十八铜人的折凳-1" aria-label="Permalink to &quot;十八铜人的折凳&quot;">​</a></h1><p>十八铜人的折凳<br> 1000<br> 科技本质</p><p>随处可见的普通折凳，并带有一丝时光的气息，凳腿是已经生了锈的铁管。</p><p>这这视为一把临时武器，伤害3l。使用时，你需要先从凳子上起身，才能起凳子砸人，这会消耗掉你的标准动作和移动动作，此次攻击中会附带一点流血点数，以标准形式豁免。于此同时，你的此次攻击将视为拥有无支线级别的措手不及。</p><p>备注：折凳，可藏于民居之中，随手可得；亦可坐于其上，隐藏杀机；由于不算凶器，即使被警察抓了，他们也告不了你。被誉为市井械斗七武器之首。</p><p>特殊的是，该凳子需有人坐在上面才能生效，同时如果非使用者本人坐在上面，则需要进行一次平衡对抗，胜出才能抽出凳子。其余情况由st判断</p><hr><p>Copyright ? 2023 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',8)])])}const m=t(d,[["render",p]]);export{f as __pageData,m as default};
